mapper.insert:
INSERT INTO
    authorization_code_info (
        code_value
        , code_challenge
        , expiration_date_time
        , is_deleted
    ) 
VALUES (
    #{codeValue}
    , #{codeChallenge}
    , #{expirationDateTime}
    , #{isDeleted}
)

mapper.select:
SELECT code_value , code_challenge FROM authorization_code_info
is_deleted = 0
AND code_value = #{codeValue}
AND expiration_date_time > #{nowDate}
